changeSet.sql:
DECLARE @course1Id BIGINT;
DECLARE @course2Id BIGINT;
DECLARE @user1Id BIGINT;

SELECT @course1Id = id FROM course WHERE title = 'course_1';
SELECT @course2Id = id FROM course WHERE title = 'course_2';

SELECT TOP 1 @user1Id = ur.user_id
    FROM user_role ur
    JOIN role r ON ur.role_id = r.id
    WHERE r.name = 'student';

INSERT INTO enrollment (course_id, user_id, completed_at)
VALUES
    (@course1Id, @user1Id, NULL),
    (@course2Id, @user1Id, GETDATE());
